const raw = $json.output[0].content[0].text;
const parsed = JSON.parse(raw);

return [
  {
    json: parsed
  }
];

const items = $input.all();

const excluded = ["submittedAt", "formMode"];
const qaPairs = [];

const data = items[0].json;

for (const key in data) {
  if (!excluded.includes(key)) {
    qaPairs.push({
      question: key,
      answer: data[key]
    });
  }
}

return [
  {
    json: {
      qaPairs
    }
  }
];

const rawText = $input.first().json.output[0].content[0].text || "";

// Extract To
const toMatch = rawText.match(/To:\s*(.*)/i);

// Extract Subject
const subjectMatch = rawText.match(/Subject:\s*(.*)/i);

// Extract everything after Subject
let emailContent = "";
if (subjectMatch) {
  const subjectLine = subjectMatch[0];
  const subjectIndex = rawText.indexOf(subjectLine);

  if (subjectIndex !== -1) {
    emailContent = rawText.slice(subjectIndex + subjectLine.length).trim();
  }
}

// Convert escaped characters into proper text
emailContent = emailContent
  .replace(/\\n/g, "\n")
  .replace(/\\r/g, "")
  .replace(/\\"/g, '"')
  .replace(/\\'/g, "'")
  .replace(/\\\\/g, "\\");

// Remove leading colon if present accidentally
emailContent = emailContent.replace(/^:\s*/, "").trim();

const result = {
  To: toMatch ? toMatch[1].trim() : "",
  Subject: subjectMatch ? subjectMatch[1].trim() : "",
  "Email content": emailContent
};

return [
  {
    json: result
  }
];

const rawText = $input.first().json.output[0].content[0].text || "";

const questions = rawText
  .replace(/^Screening Questions:\s*/i, "")
  .split(/\n+/)
  .map(q => q.trim())
  .filter(q => q.length > 0);

return [
  {
    json: {
      screening_questions: questions
    }
  }
];
